// surface every error rather than silently swallowing it.
const autumnStrict = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY,
  failOpen: false,
});

/**
 * Check whether a customer is allowed to use a feature.
 *
 * On any error (network failure, timeout, 5xx, etc.) the function logs a
 * warning to stderr and returns { allowed: true, source: 'fail-open' } so
 * that the application keeps running even when Autumn is unreachable.
 *
 * @param {string} customerId  - Autumn customer ID
 * @param {string} featureId   - Autumn feature ID
 * @returns {Promise<{ allowed: boolean, source: string }>}
 */
export async function resilientCheck(customerId, featureId) {
  try {
    const result = await autumn.check({ customerId, featureId });
    return { allowed: result.allowed, source: 'autumn' };
  } catch (err) {
    process.stderr.write('AUTUMN UNREACHABLE, FAILING OPEN\n');
    return { allowed: true, source: 'fail-open' };
  }
}

